    val businessOrder = listOf("electronics", "grocery", "pharmacy", "restaurant")
    val businessMap = businessOrder.withIndex().associate { (index, line) -> line to index }

    val validCoupons = mutableListOf<Pair<String, String>>()

    for (i in code.indices) {
        val c = code[i]
        val bl = businessLine[i]
        val active = isActive[i]

        if (c.isEmpty()) continue
        if (!c.matches(Regex("^[a-zA-Z0-9_]+$"))) continue
        if (bl !in businessMap) continue
        if (!active) continue

        validCoupons.add(Pair(bl, c))
    }

    val sortedCoupons = validCoupons.sortedWith(compareBy { businessMap[it.first] } { it.second })

    return sortedCoupons.map { it.second }.toTypedArray()
}
