using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> business_order = {"electronics", "grocery", "pharmacy", "restaurant"};
    map<string, int> business_map;
    for (int i = 0; i < business_order.size(); ++i) {
        business_map[business_order[i]] = i;
    }

    vector<pair<string, string>> valid_coupons;

    for (int i = 0; i < code.size(); ++i) {
        if (code[i].empty()) continue;
        regex pattern("^[a-zA-Z0-9_]+$");
        if (!regex_match(code[i], pattern)) continue;

        auto it = business_map.find(businessLine[i]);
        if (it == business_map.end()) continue;

        if (!isActive[i]) continue;

        valid_coupons.push_back({businessLine[i], code[i]});
    }

    sort(valid_coupons.begin(), valid_coupons.end(), 
        [&](const pair<string, string>& a, const pair<string, string>& b) {
            int idx_a = business_map[a.first];
            int idx_b = business_map[b.first];
            if (idx_a != idx_b) return idx_a < idx_b;
            return a.second < b.second;
        });

    vector<string> result;
    for (const auto& p : valid_coupons) {
        result.push_back(p.second);
    }

    return result;
}
